// Aggregate daily KPIs
// In production: query Supabase api_usage_log, agent_executions, kanban_tasks
const today = new Date().toISOString().split('T')[0];

const report = {
  date: today,
  summary: {
    totalAgentTasks: 142,
    completedTasks: 136,
    failedTasks: 3,
    pendingTasks: 3,
    successRate: 95.8,
    totalTokensUsed: 487500,
    totalCostUsd: 12.47,
    avgResponseTimeMs: 1450,
    phiEventsDetected: 7,
    phiEventsRedacted: 7,
    n8nWorkflowsExecuted: 45,
    n8nWorkflowsFailed: 1
  },
  topAgents: [
    { name: 'Dr. Front Desk', tasks: 47, successRate: 96.2 },
    { name: 'InsureBot', tasks: 31, successRate: 98.1 },
    { name: 'Marketing Maven', tasks: 23, successRate: 100 }
  ],
  alerts: [],
  generatedAt: new Date().toISOString(),
  source: 'n8n-ops-reporting'
};

// Check for alerts
if (report.summary.successRate < 90) {
  report.alerts.push({ level: 'warning', message: `Success rate below 90%: ${report.summary.successRate}%` });
}
if (report.summary.totalCostUsd > 50) {
  report.alerts.push({ level: 'warning', message: `Daily cost exceeded $50: $${report.summary.totalCostUsd}` });
}

return [{ json: report }];

const report = $input.first().json;

// Format as Slack-friendly message
const blocks = [
  `*Daily Operations Report — ${report.date}*`,
  '',
  `Tasks: ${report.summary.completedTasks}/${report.summary.totalAgentTasks} completed (${report.summary.successRate}%)`,
  `Cost: $${report.summary.totalCostUsd.toFixed(2)} | Tokens: ${(report.summary.totalTokensUsed / 1000).toFixed(1)}k`,
  `PHI Events: ${report.summary.phiEventsDetected} detected, ${report.summary.phiEventsRedacted} redacted`,
  `Workflows: ${report.summary.n8nWorkflowsExecuted} executed, ${report.summary.n8nWorkflowsFailed} failed`,
  '',
  '*Top Agents:*',
  ...report.topAgents.map(a => `  ${a.name}: ${a.tasks} tasks (${a.successRate}%)`),
];

if (report.alerts.length > 0) {
  blocks.push('', '*Alerts:*');
  report.alerts.forEach(a => blocks.push(`  :warning: ${a.message}`));
}

return [{ json: { report, formattedMessage: blocks.join('\n') } }];

